1903	// executeLoopWithServer submits an execute-loop job to the running ddx server.
1904	// The server starts a background worker and returns its ID.
1905	func (f *CommandFactory) executeLoopWithServer(cmd *cobra.Command, projectRoot, harness, model, profile, provider, modelRef, effort string, once bool, pollInterval time.Duration, asJSON bool, noReview bool, reviewHarness, reviewModel string) error {
1906		serverBase := resolveServerURL(projectRoot)
1907	
1908		workerSpec := map[string]any{
1909			"once":         once,
1910			"project_root": projectRoot,
1911		}
1912		if harness != "" {
1913			workerSpec["harness"] = harness
1914		}
1915		if model != "" {
1916			workerSpec["model"] = model
1917		}
1918		if profile != "" {
1919			workerSpec["profile"] = profile
1920		}
1921		if provider != "" {
1922			workerSpec["provider"] = provider
1923		}
1924		if modelRef != "" {
1925			workerSpec["model_ref"] = modelRef
1926		}
1927		if effort != "" {
1928			workerSpec["effort"] = effort
1929		}
1930		if pollInterval > 0 {
1931			workerSpec["poll_interval"] = pollInterval.String()
1932		}
1933		if noReview {
1934			workerSpec["no_review"] = true
1935		}
1936		if reviewHarness != "" {
1937			workerSpec["review_harness"] = reviewHarness
1938		}
1939		if reviewModel != "" {
1940			workerSpec["review_model"] = reviewModel
1941		}
1942		specData, err := json.Marshal(workerSpec)
1943		if err != nil {
1944			return fmt.Errorf("marshal worker spec: %w", err)
1945		}
1946	
1947		reqURL := serverBase + "/api/agent/workers/execute-loop"
1948		req, err := http.NewRequestWithContext(cmd.Context(), http.MethodPost, reqURL, bytes.NewReader(specData))
1949		if err != nil {
1950			return err
1951		}
1952		req.Header.Set("Content-Type", "application/json")
1953	
1954		client := newLocalServerClient()
1955		resp, err := client.Do(req)
1956		if err != nil {
1957			return fmt.Errorf("submit to server %s: %w\n  Hint: start the server with 'ddx server'", serverBase, err)
1958		}
1959		defer func() { _ = resp.Body.Close() }()
1960	
1961		if resp.StatusCode == http.StatusServiceUnavailable {
1962			return fmt.Errorf("server is running but no project is loaded for this directory\n  Hint: start the server from the project root")
1963		}
1964		if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
1965			body, _ := io.ReadAll(resp.Body)
1966			return fmt.Errorf("server error (%d): %s", resp.StatusCode, strings.TrimSpace(string(body)))
1967		}
1968	
1969		var workerRecord struct {
1970			ID          string `json:"id"`
1971			State       string `json:"state"`
1972			ProjectRoot string `json:"project_root"`
1973			Harness     string `json:"harness,omitempty"`
1974			Model       string `json:"model,omitempty"`
1975			Once        bool   `json:"once"`
1976		}
1977		if err := json.NewDecoder(resp.Body).Decode(&workerRecord); err != nil {
1978			body, _ := io.ReadAll(resp.Body)
1979			return fmt.Errorf("parse server response: %w: %s", err, string(body))
1980		}
1981	
1982		if asJSON {
1983			enc := json.NewEncoder(cmd.OutOrStdout())
1984			enc.SetIndent("", "  ")
1985			return enc.Encode(map[string]any{
1986				"worker_id":    workerRecord.ID,
1987				"state":        workerRecord.State,
1988				"project_root": workerRecord.ProjectRoot,
1989				"harness":      workerRecord.Harness,
1990				"model":        workerRecord.Model,
1991				"once":         workerRecord.Once,
1992			})
1993		}
1994	
1995		fmt.Fprintf(cmd.OutOrStdout(), "worker:   %s\n", workerRecord.ID)
1996		fmt.Fprintf(cmd.OutOrStdout(), "state:    %s\n", workerRecord.State)
1997		fmt.Fprintf(cmd.OutOrStdout(), "project:  %s\n", workerRecord.ProjectRoot)
1998		if workerRecord.Harness != "" {
1999			fmt.Fprintf(cmd.OutOrStdout(), "harness:  %s\n", workerRecord.Harness)
2000		}
2001		if workerRecord.Model != "" {
2002			fmt.Fprintf(cmd.OutOrStdout(), "model:    %s\n", workerRecord.Model)
2003		}
2004		if workerRecord.Once {
2005			fmt.Fprintln(cmd.OutOrStdout(), "once:     true")
2006		}
2007		fmt.Fprintln(cmd.OutOrStdout(), "")
2008		fmt.Fprintf(cmd.OutOrStdout(), "Monitor progress: ddx server workers show %s\n", workerRecord.ID)
2009		fmt.Fprintf(cmd.OutOrStdout(), "View logs:        ddx server workers log %s\n", workerRecord.ID)
2010		return nil
2011	}
