2013	// resolveProjectRoot returns the project root to use for execute-loop,
2014	// execute-bead, and agent-run commands. Resolution order:
2015	//  1. --project flag value (if non-empty)
2016	//  2. DDX_PROJECT_ROOT environment variable
2017	//  3. CWD-based git project root detection (gitpkg.FindProjectRoot)
2018	func resolveProjectRoot(projectFlag, workingDir string) string {
2019		if projectFlag != "" {
2020			return projectFlag
2021		}
2022		if env := os.Getenv("DDX_PROJECT_ROOT"); env != "" {
2023			return env
2024		}
2025		return gitpkg.FindProjectRoot(workingDir)
2026	}
