2028	// buildCLIPreClaimHook returns a PreClaimHook for the --local execute-loop
2029	// that fetches origin and verifies ancestry before each bead claim. Fetch
2030	// failures are logged but do not block the worker (air-gap friendly).
2031	func buildCLIPreClaimHook(projectRoot string, gitOps agent.LandingGitOps) func(ctx context.Context) error {
2032		return func(ctx context.Context) error {
2033			branch, err := gitOps.CurrentBranch(projectRoot)
2034			if err != nil {
2035				return nil // can't determine branch — skip
2036			}
2037			res, err := gitOps.FetchOriginAncestryCheck(projectRoot, branch)
2038			if err != nil {
2039				return nil // fetch failure is non-fatal
2040			}
2041			if res.Action == "diverged" {
2042				return fmt.Errorf("local branch %s has diverged from origin (local=%s origin=%s); reconcile manually before claiming",
2043					branch, res.LocalSHA, res.OriginSHA)
2044			}
2045			return nil
2046		}
2047	}
