2049	// resolveServerURL determines the base URL for the running DDx server.
2050	//
2051	// Resolution order (matches internal/serverreg):
2052	//  1. DDX_SERVER_URL environment variable (explicit override)
2053	//  2. ~/.local/share/ddx/server.addr (written by `ddx server` on startup)
2054	//  3. https://127.0.0.1:7743 (the canonical default — see FEAT-020)
2055	//
2056	// The addr file may record a bind-address URL like https://0.0.0.0:7743
2057	// (because the server binds to 0.0.0.0 for multi-interface access). Those
2058	// are valid listen addresses but not reachable as client targets on some
2059	// platforms — rewrite them to https://127.0.0.1:<port> for local clients.
2060	//
2061	// The probe-common-ports heuristic that used to live here only worked for
2062	// the legacy plaintext http://127.0.0.1:8080 setup and never honored the
2063	// TLS default that's been in place since alpha13. Clients that skipped
2064	// the addr file would silently get a connection refused and tell the
2065	// user the server wasn't running when it was listening on 7743.
2066	func resolveServerURL(projectRoot string) string {
2067		if u := os.Getenv("DDX_SERVER_URL"); u != "" {
2068			return u
2069		}
2070		if u := serverpkg.ReadServerAddr(); u != "" {
2071			return rewriteBindAddrForClient(u)
2072		}
2073		return "https://127.0.0.1:7743"
2074	}
2075	
2076	// rewriteBindAddrForClient converts a bind-address URL into a client-reachable
2077	// URL. 0.0.0.0 (and [::]) are valid listen addresses but not reachable as
2078	// client destinations on all platforms — substitute 127.0.0.1 so local HTTP
2079	// clients can always connect.
2080	func rewriteBindAddrForClient(u string) string {
2081		for _, bind := range []string{"//0.0.0.0:", "//[::]:", "//[::0]:"} {
2082			if idx := strings.Index(u, bind); idx >= 0 {
2083				return u[:idx] + "//127.0.0.1:" + u[idx+len(bind):]
2084			}

